    int32_t params[9];
    for (int i = 0; i < 9; i++)
        params[i] = Int_val(Field(v_params, i));
    int32_t out[5];
    memset(out, 0, sizeof(out));
    if (g_path_fvi_query)
        g_path_fvi_query(params, out);
    v_result = caml_alloc(5, 0);
    for (int i = 0; i < 5; i++)
        Store_field(v_result, i, Val_long(out[i]));
    CAMLreturn(v_result);
}

