					//              -> [hit_type, hit_x, hit_y, hit_z, hit_seg]
					[](const int32_t* params, int32_t* out) {
						vms_vector p0 = {params[0], params[1], params[2]};
						vms_vector p1 = {params[4], params[5], params[6]};
						fvi_info hit_data;
						fvi_query fq;
						fq.p0 = &p0;
